import { PropsWithChildren, useState } from 'react';
import { makeStyles, Typography, ButtonBase, Collapse } from '@material-ui/core';
import HomeIcon from '@material-ui/icons/Home';
import ExtensionIcon from '@material-ui/icons/Extension';
import BuildIcon from '@material-ui/icons/Build';
import LogoFull from './LogoFull';
import LogoIcon from './LogoIcon';
import {
  Sidebar,
  sidebarConfig,
  SidebarDivider,
  SidebarGroup,
  SidebarItem,
  SidebarPage,
  SidebarSpace,
  useSidebarOpenState,
  Link,
} from '@backstage/core-components';
import HistoryIcon from '@material-ui/icons/History';
import MenuIcon from '@material-ui/icons/Menu';
import SettingsIcon from '@material-ui/icons/Settings';
import LinkIcon from '@material-ui/icons/Link';
import SyncIcon from '@material-ui/icons/Sync';
import LockIcon from '@material-ui/icons/Lock';
import GitHubIcon from '@material-ui/icons/GitHub';
import ExpandLessIcon from '@material-ui/icons/ExpandLess';
import ExpandMoreIcon from '@material-ui/icons/ExpandMore';

const useSidebarLogoStyles = makeStyles({
  root: {
    width: sidebarConfig.drawerWidthClosed,
    height: 3 * sidebarConfig.logoHeight,
    display: 'flex',
    flexFlow: 'row nowrap',
    alignItems: 'center',
    marginBottom: -14,
  },
  link: {
    width: sidebarConfig.drawerWidthClosed,
    marginLeft: 24,
  },
});

const useAdminDrawerStyles = makeStyles(theme => ({
  drawerHeader: {
    display: 'flex',
    alignItems: 'center',
    width: '100%',
    height: 48,
    padding: 0,
    paddingLeft: 24,
    paddingRight: 20,
    cursor: 'pointer',
    background: 'none',
    border: 'none',
    textAlign: 'left',
    color: theme.palette.navigation?.color ?? theme.palette.text.primary,
    '&:hover': {
      background: theme.palette.navigation?.navItem?.hoverBackground ?? (
        theme.palette.type === 'dark' ? 'rgba(255,255,255,0.08)' : 'rgba(0,0,0,0.04)'
      ),
    },
  },
  arrow: {
    fontSize: 20,
    color: theme.palette.navigation?.color ?? theme.palette.text.secondary,
    marginRight: 4,
  },
  icon: {
    fontSize: 20,
    color: theme.palette.navigation?.color ?? theme.palette.text.secondary,
  },
  label: {
    fontSize: theme.typography.body2.fontSize,
    fontWeight: theme.typography.fontWeightRegular as number,
    color: theme.palette.navigation?.color ?? theme.palette.text.primary,
    marginLeft: theme.spacing(1),
    flex: 1,
    whiteSpace: 'nowrap',
    overflow: 'hidden',
    textOverflow: 'ellipsis',
  },
}));

const AdminDrawer = () => {
  const [open, setOpen] = useState(false);
  const classes = useAdminDrawerStyles();
  const { isOpen: sidebarIsOpen } = useSidebarOpenState();

  return (
    <div>
      <ButtonBase
        className={classes.drawerHeader}
        onClick={() => setOpen(!open)}
        aria-expanded={open}
        aria-label="Administration"
      >
        {open ? (
          <ExpandLessIcon className={classes.arrow} />
        ) : (
          <ExpandMoreIcon className={classes.arrow} />
        )}
        <SettingsIcon className={classes.icon} />
        {sidebarIsOpen && (
          <Typography className={classes.label}>
            Administration
          </Typography>
        )}
      </ButtonBase>
      <Collapse in={open}>
        <SidebarItem icon={SettingsIcon} to="/self-service/admin/general" text="General" />
        <SidebarItem icon={LinkIcon} to="/self-service/admin/integrations" text="Integrations" />
        <SidebarItem icon={SyncIcon} to="/self-service/admin/sync-activity" text="Sync Status" />
        <SidebarItem icon={LockIcon} to="/rbac" text="Access Control" />
      </Collapse>
    </div>
  );
};

const SidebarLogo = () => {
  const classes = useSidebarLogoStyles();
  const { isOpen } = useSidebarOpenState();

  return (
    <div className={classes.root}>
      <Link to="/" underline="none" className={classes.link} aria-label="Home">
        {isOpen ? <LogoFull /> : <LogoIcon />}
      </Link>
    </div>
  );
};

export const Root = ({ children }: PropsWithChildren<{}>) => (
  <SidebarPage>
    <Sidebar>
      <SidebarLogo />
      <SidebarGroup label="Menu" icon={<MenuIcon />}>
        <SidebarItem
          icon={HomeIcon}
          to="/self-service/catalog"
          text="Templates"
        />
        <SidebarItem
          icon={HistoryIcon}
          to="/self-service/create/tasks"
          text="History"
        />
        <SidebarDivider />
        <SidebarItem
          icon={GitHubIcon}
          to="/self-service/repositories"
          text="Git Repositories"
        />
        <SidebarItem
          icon={BuildIcon}
          to="/self-service/ee"
          text="Execution Env."
        />
        <SidebarItem
          icon={ExtensionIcon}
          to="/self-service/collections"
          text="Collections"
        />
      </SidebarGroup>
      <SidebarSpace />
      <SidebarDivider />
      <AdminDrawer />
    </Sidebar>
    {children}
  </SidebarPage>
);
