// @ts-nocheck
import {
  CatalogApi,
  GetEntitiesRequest,
  GetEntitiesResponse,
  GetEntityByRefRequest,
  CatalogRequestOptions,
  GetEntitiesByRefsRequest,
  GetEntitiesByRefsResponse,
  QueryEntitiesRequest,
  QueryEntitiesResponse,
} from '@backstage/catalog-client';
import { Entity, CompoundEntityRef, stringifyEntityRef } from '@backstage/catalog-model';
import { ALL_DEMO_ENTITIES } from './demoCatalogData';

export class DemoCatalogClient implements CatalogApi {
  private entities: Entity[] = ALL_DEMO_ENTITIES;

  async getEntities(request?: GetEntitiesRequest, _options?: CatalogRequestOptions): Promise<GetEntitiesResponse> {
    let filtered = [...this.entities];

    if (request?.filter) {
      const filters = Array.isArray(request.filter) ? request.filter : [request.filter];
      filtered = filtered.filter(entity => {
        return filters.some(filterGroup => {
          return Object.entries(filterGroup).every(([key, values]) => {
            const vals = Array.isArray(values) ? values : [values];
            const entityValue = this.getEntityField(entity, key);
            if (!entityValue) return false;
            return vals.some(v => entityValue.toLowerCase() === v.toLowerCase());
          });
        });
      });
    }

    return { items: filtered };
  }

  async getEntityByRef(nameOrRef: string | CompoundEntityRef | GetEntityByRefRequest, _options?: CatalogRequestOptions): Promise<Entity | undefined> {
    const ref = typeof nameOrRef === 'string' ? nameOrRef
      : 'entityRef' in nameOrRef ? (nameOrRef as GetEntityByRefRequest).entityRef
      : stringifyEntityRef(nameOrRef as CompoundEntityRef);
    return this.entities.find(e => stringifyEntityRef(e as any) === ref);
  }

  async getEntitiesByRefs(request: GetEntitiesByRefsRequest, _options?: CatalogRequestOptions): Promise<GetEntitiesByRefsResponse> {
    const items = request.entityRefs.map(ref =>
      this.entities.find(e => stringifyEntityRef(e as any) === ref) || undefined
    );
    return { items: items as (Entity | undefined)[] };
  }

  async queryEntities(request?: QueryEntitiesRequest, _options?: CatalogRequestOptions): Promise<QueryEntitiesResponse> {
    let filtered = [...this.entities];

    if (request?.filter) {
      const filters = Array.isArray(request.filter) ? request.filter : [request.filter];
      filtered = filtered.filter(entity => {
        return filters.some(filterGroup => {
          return Object.entries(filterGroup).every(([key, values]) => {
            const vals = Array.isArray(values) ? values : [values];
            const entityValue = this.getEntityField(entity, key);
            if (!entityValue) return false;
            return vals.some(v => entityValue.toLowerCase() === v.toLowerCase());
          });
        });
      });
    }

    if (request?.fullTextFilter?.term) {
      const term = request.fullTextFilter.term.toLowerCase();
      filtered = filtered.filter(e =>
        (e.metadata.name || '').toLowerCase().includes(term) ||
        (e.metadata.title || '').toLowerCase().includes(term) ||
        (e.metadata.description || '').toLowerCase().includes(term)
      );
    }

    const limit = request?.limit || 20;
    const offset = request?.offset ? Number(request.offset) : 0;
    const page = filtered.slice(offset, offset + limit);

    return {
      items: page,
      totalItems: filtered.length,
      pageInfo: {
        nextCursor: offset + limit < filtered.length ? String(offset + limit) : undefined,
        prevCursor: offset > 0 ? String(Math.max(0, offset - limit)) : undefined,
      },
    };
  }

  async removeEntityByUid(_uid: string, _options?: CatalogRequestOptions): Promise<void> {}
  async refreshEntity(_entityRef: string, _options?: CatalogRequestOptions): Promise<void> {}
  async getEntityFacets(_request: any, _options?: CatalogRequestOptions): Promise<any> {
    return { facets: {} };
  }
  async getLocationById(_id: string, _options?: CatalogRequestOptions): Promise<any> { return undefined; }
  async getLocationByRef(_locationRef: string, _options?: CatalogRequestOptions): Promise<any> { return undefined; }
  async addLocation(_location: any, _options?: CatalogRequestOptions): Promise<any> { return { location: {}, entities: [] }; }
  async removeLocationById(_id: string, _options?: CatalogRequestOptions): Promise<void> {}
  async validateEntity(_entity: Entity, _locationRef: string, _options?: CatalogRequestOptions): Promise<any> { return {}; }

  private getEntityField(entity: Entity, key: string): string | undefined {
    switch (key) {
      case 'kind': return entity.kind;
      case 'metadata.name': return entity.metadata.name;
      case 'metadata.namespace': return entity.metadata.namespace || 'default';
      case 'spec.type': return (entity.spec as any)?.type;
      case 'spec.lifecycle': return (entity.spec as any)?.lifecycle;
      case 'spec.owner': return (entity.spec as any)?.owner;
      default:
        if (key.startsWith('metadata.annotations.')) {
          const annotationKey = key.replace('metadata.annotations.', '');
          return entity.metadata.annotations?.[annotationKey];
        }
        if (key.startsWith('metadata.')) {
          return (entity.metadata as any)?.[key.replace('metadata.', '')];
        }
        if (key.startsWith('spec.')) {
          return (entity.spec as any)?.[key.replace('spec.', '')];
        }
        return undefined;
    }
  }
}
